  ('aboriginal-57f41407-moex-00168', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '有關行政罰法之原則的敘述，下列何者錯誤？', '["行政罰法有從新從輕原則之適用", "在中華民國領域內違反行政法上義務受處罰，原則上適用行政罰法", "對當事人課以行政罰須符合故意或過失的責任條件", "行政機關不能成為課處行政罰的對象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
